:"\n<div class="wp-block-media-text alignfull is-stacked-on-mobile is-vertically-aligned-center"><figure class="wp-block-media-text__media"><img decoding="async" src="https://s.w.org/images/core/5.8/architecture-04.jpg" alt="Zbliżenie, abstrakcyjny widok na architekturę." /></figure><div class="wp-block-media-text__content">\n<h3 class="wp-block-heading has-text-align-center has-text-color" style="color:#000000"><strong>Otwarte przestrzenie</strong></h3>\n\n\n\n<p class="has-text-align-center has-extra-small-font-size wp-block-paragraph"><a href="#">Zobacz przypadek użycia <span aria-hidden="true" class="wp-exclude-emoji">↗</span></a></p>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:70:"Blok medialno-tekstowy z obrazem po lewej i tekstem po prawej stronie.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:1:{i:0;s:0:"";}s:11:"wpop_locale";s:5:"pl_PL";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:43:"core/heading,core/media-text,core/paragraph";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:6:"banner";}s:13:"keyword_slugs";a:2:{i:0;s:4:"core";i:1;s:8:"featured";}s:15:"pattern_content";s:871:"<!-- wp:media-text {"align":"full","mediaType":"image","verticalAlignment":"center"} -->\n<div class="wp-block-media-text alignfull is-stacked-on-mobile is-vertically-aligned-center"><figure class="wp-block-media-text__media"><img src="https://s.w.org/images/core/5.8/architecture-04.jpg" alt="Zbliżenie, abstrakcyjny widok na architekturę." /></figure><div class="wp-block-media-text__content"><!-- wp:heading {"textAlign":"center","level":3,"style":{"color":{"text":"#000000"}}} -->\n<h3 class="wp-block-heading has-text-align-center has-text-color" style="color:#000000"><strong>Otwarte przestrzenie</strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"align":"center","fontSize":"extra-small"}