/files/2021/06/wire-sculpture-263x300.jpg 263w, https://s.w.org/patterns/files/2021/06/wire-sculpture-898x1024.jpg 898w, https://s.w.org/patterns/files/2021/06/wire-sculpture-768x875.jpg 768w, https://s.w.org/patterns/files/2021/06/wire-sculpture-1347x1536.jpg 1347w, https://s.w.org/patterns/files/2021/06/wire-sculpture.jpg 1658w" sizes="auto, (max-width: 263px) 100vw, 263px" /></figure></div>\n</div></div>\n</div>\n\n\n\n<div class="wp-block-column is-vertically-aligned-center is-layout-flow wp-block-column-is-layout-flow" style="padding-top:1em;padding-right:1em;padding-bottom:1em;padding-left:1em">\n<div class="wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow" style="flex-basis:320px">\n<p class="has-small-font-size wp-block-paragraph" style="line-height:1.6"><strong>Airplane</strong></p>\n\n\n\n<p class="has-small-font-size wp-block-paragraph" style="line-height:1.6">Copper wire, wood base. I created this piece in late 2008. For this work, I aimed to convey both the industrial heaviness of an airplane, but also the cloudlike floating quality you feel when you’re in one.</p>\n</div>\n</div>\n</div>\n</div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:38:"Image on solid color with description.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:61:"core/column,core/columns,core/cover,core/image,core/paragraph";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:2:{i:0;s:6:"images";i:1;s:4:"text";}s:13:"keyword_slugs";a:1:{i:0;s:8:"featured";}s:15:"pattern_content";s:1826:"<!-- wp:columns {"align":"full"} -->\n<div class="wp-block-columns alignfull"><!-- wp:column {"width":"50%"} -->\n<div class