	(83, 34, '_wp_attached_file', '2026/04/Create_a_premium_202604141428.jpg'),
	(84, 34, '_wp_attachment_metadata', 'a:6:{s:5:"width";i:2048;s:6:"height";i:2048;s:4:"file";s:41:"2026/04/Create_a_premium_202604141428.jpg";s:8:"filesize";i:2527971;s:5:"sizes";a:5:{s:6:"medium";a:5:{s:4:"file";s:41:"Create_a_premium_202604141428-300x300.jpg";s:5:"width";i:300;s:6:"height";i:300;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:18594;}s:5:"large";a:5:{s:4:"file";s:43:"Create_a_premium_202604141428-1024x1024.jpg";s:5:"width";i:1024;s:6:"height";i:1024;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:134856;}s:9:"thumbnail";a:5:{s:4:"file";s:41:"Create_a_premium_202604141428-150x150.jpg";s:5:"width";i:150;s:6:"height";i:150;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:6351;}s:12:"medium_large";a:5:{s:4:"file";s:41:"Create_a_premium_202604141428-768x768.jpg";s:5:"width";i:768;s:6:"height";i:768;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:82302;}s:9:"1536x1536";a:5:{s:4:"file";s:43:"Create_a_premium_202604141428-1536x1536.jpg";s:5:"width";i:1536;s:6:"height";i:1536;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:251913;}}s:10:"image_meta";a:12:{s:8:"aperture";s:1:"0";s:6:"credit";s:0:"";s:6:"camera";s:0:"";s:7:"caption";s:0:"";s:17:"created_timestamp";s:1:"0";s:9:"copyright";s:0:"";s:12:"focal_length";s:1:"0";s:3:"iso";s:1:"0";s:13:"shutter_speed";s:1:"0";s:5:"title";s:0:"";s:11:"orientation";s:1:"0";s:8:"keywords";a:0:{}}}'),
	(85, 32, '_thumbnail_id', '34'),
	(86, 35, '_edit_last', '1'),
	(87, 35, '_edit_lock', '1776182936:1'),
	(88, 35, 'subheader', 'Dokumenty, które chronią Twoje interesy'),
	(89, 35, '_subheader', 'field_69de209e31b98'),
	(90, 35, 'introduction', 'Umowa to podstawa każdej współpracy – niezależnie od tego, czy dotyczy kupna, sprzedaży,\r\nwynajmu, zlecenia, świadczenia usług czy innej czynności prawnej. Dobrze przygotowana umowa\r\nchroni Twoje interesy, zapobiega nieporozumieniom i pozwala uniknąć kosztownych sporów w\r\nprzyszłości.'),
	(91, 35, '_introduction', 'field_69de2113c5eb1'),
	(92, 35, 'good_to_know', 'Nasza kancelaria zajmuje się profesjonalnym sporządzaniem, opiniowaniem i negocjowaniem umów – zarówno dla klientów indywidualnych, jak i firm.\r\nTworzymy dokumenty dopasowane do konkretnej sytuacji, jasne, zgodne z obowiązującym prawem i zabezpieczające Twoje prawa.\r\n\r\n&nbsp;\r\n\r\n<strong>Pomagamy m.in. w zakresie:</strong>\r\n<ul>\r\n 	<li>umów cywilnoprawnych (sprzedaży, darowizny, najmu, pożyczki, zlecenia, o dzieło),</li>\r\n 	<li>umów handlowych i biznesowych,</li>\r\n 	<li>umów pracowniczych i kontraktów menedżerskich,</li>\r\n 	<li>umów wspólników i inwestycyjnych, związanych z działalnością spółek,</li>\r\n 	<li>przygotowania aneksów i porozumień rozwiązujących.</li>\r\n</ul>\r\n&nbsp;\r\n\r\nJeśli masz gotową umowę i nie jesteś pewien, czy jest dla Ciebie korzystna – przeanalizujemy ją i wskażemy ewentualne ryzyka.\r\n\r\nJeżeli dopiero chcesz sporządzić umowę – przygotujemy ją tak, by była przejrzysta, skuteczna i bezpieczna.\r\n\r\n&nbsp;\r\n\r\nSkontaktuj się z nami – <strong>zadbaj o swoje interesy, zanim złożysz podpis.</strong>'),
