	(115, 35, '_service_list_3_service_list_item', 'field_69de21adc5eb4'),
	(116, 35, 'service_list_4_service_list_item', 'Wsparcie przy opiniowaniu, negocjowaniu i wprowadzaniu zmian do dokumentu'),
	(117, 35, '_service_list_4_service_list_item', 'field_69de21adc5eb4'),
	(118, 35, 'service_list_5_service_list_item', 'Większe bezpieczeństwo prawne w relacjach prywatnych i biznesowych'),
	(119, 35, '_service_list_5_service_list_item', 'field_69de21adc5eb4'),
	(120, 35, 'faq_list_0_faq_question', 'Czy mogę zlecić sprawdzenie gotowej umowy?'),
	(121, 35, '_faq_list_0_faq_question', 'field_69de21fcc5eb6'),
	(122, 35, 'faq_list_0_faq_answear', 'Tak. Analizujemy również gotowe projekty umów i wskazujemy, czy ich treść jest korzystna, jakie ryzyka się z nimi wiążą oraz które zapisy warto zmienić, doprecyzować lub usunąć przed podpisaniem.'),
	(123, 35, '_faq_list_0_faq_answear', 'field_69de220ac5eb7'),
	(124, 35, 'faq_list_1_faq_question', 'Czy przygotowujecie umowy zarówno dla osób prywatnych, jak i przedsiębiorców?'),
	(125, 35, '_faq_list_1_faq_question', 'field_69de21fcc5eb6'),
	(126, 35, 'faq_list_1_faq_answear', 'Tak. Sporządzamy i opiniujemy dokumenty zarówno dla klientów indywidualnych, jak i dla firm. Każdą umowę przygotowujemy z uwzględnieniem konkretnej sytuacji, charakteru współpracy oraz interesów klienta.'),
	(127, 35, '_faq_list_1_faq_answear', 'field_69de220ac5eb7'),
	(128, 35, 'faq_list_2_faq_question', 'Dlaczego warto skonsultować umowę przed jej podpisaniem?'),
	(129, 35, '_faq_list_2_faq_question', 'field_69de21fcc5eb6'),
	(130, 35, 'faq_list_2_faq_answear', 'Podpisanie nieprzeanalizowanej umowy może prowadzić do nieporozumień, strat finansowych lub trudności w dochodzeniu swoich praw. Wcześniejsza analiza pozwala wychwycić niekorzystne zapisy i zadbać o to, aby dokument był bezpieczny, przejrzysty i skuteczny.'),
	(131, 35, '_faq_list_2_faq_answear', 'field_69de220ac5eb7'),
	(132, 37, '_wp_attached_file', '2026/04/umowy-i-pisma.jpg'),
	(133, 37, '_wp_attachment_metadata', 'a:6:{s:5:"width";i:2048;s:6:"height";i:2048;s:4:"file";s:25:"2026/04/umowy-i-pisma.jpg";s:8:"filesize";i:2208301;s:5:"sizes";a:5:{s:6:"medium";a:5:{s:4:"file";s:25:"umowy-i-pisma-300x300.jpg";s:5:"width";i:300;s:6:"height";i:300;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:14270;}s:5:"large";a:5:{s:4:"file";s:27:"umowy-i-pisma-1024x1024.jpg";s:5:"width";i:1024;s:6:"height";i:1024;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:89818;}s:9:"thumbnail";a:5:{s:4:"file";s:25:"umowy-i-pisma-150x150.jpg";s:5:"width";i:150;s:6:"height";i:150;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:5578;}s:12:"medium_large";a:5:{s:4:"file";s:25:"umowy-i-pisma-768x768.jpg";s:5:"width";i:768;s:6:"height";i:768;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:56621;}s:9:"1536x1536";a:5:{s:4:"file";s:27:"umowy-i-pisma-1536x1536.jpg";s:5:"width";i:1536;s:6:"height";i:1536;s:9:"mime-type";s:10:"image/jpeg";s:8:"filesize";i:168585;}}s:10:"image_meta";a:12:{s:8:"aperture";s:1:"0";s:6:"credit";s:0:"";s:6:"camera";s:0:"";s:7:"caption";s:0:"";s:17:"created_timestamp";s:1:"0";s:9:"copyright";s:0:"";s:12:"focal_length";s:1:"0";s:3:"iso";s:1:"0";s:13:"shutter_speed";s:1:"0";s:5:"title";s:0:"";s:11:"orientation";s:1:"0";s:8:"keywords";a:0:{}}}'),
	(134, 35, '_thumbnail_id', '37'),
	(135, 38, '_edit_last', '1'),
	(136, 38, '_edit_lock', '1776183609:1'),
	(137, 38, 'subheader', 'Wsparcie prawne na każdym etapie sporu - od analizy sytuacji po reprezentację przed sądem'),
	(138, 38, '_subheader', 'field_69de209e31b98'),
	(139, 38, 'introduction', 'W przypadku przewidywanego sporu zalecamy kontakt z Kancelarią jak najwcześniej. Konsultacja\r\njuż w początkowej fazie konfliktu często pozwoli na zminimalizowanie kosztów i stanowi niezbędną\r\nochronę przed ryzykiem przedawnienia sprawy. Rozważenie wszystkich możliwych opcji przed\r\npodjęciem się jakichkolwiek działań bardzo często pozwoli na doprowadzenie sprawy do końca w\r\nsposób możliwie najbardziej satysfakcjonujący. Doradzamy, czy postępowanie sądowe jest konieczne\r\ni czy pozostały drogi ugodowe, którymi można rozwiązać spor – a jeśli dojdzie do wszczęcia procesu,\r\npomagamy przejść przez postępowanie świadomie, odważnie i profesjonalnie.'),
	(140, 38, '_introduction', 'field_69de2113c5eb1'),
	(141, 38, 'good_to_know', 'Sprawy prowadzimy według uznania Klienta - zarówno kompleksowo, <strong>poprzez pełne zastępstwo </strong><strong>procesowe</strong> jak i tylko <strong>doradczo</strong>, udzielając porad prawnych i pomagając w formułowaniu wniosków lub pism procesowych. Profesjonalny pełnomocnik czuwa nad prawidłowym przebiegiem całego postępowania. Wspieramy na każdym etapie sporu – od pierwszego kontaktu z drugą stroną aż po postępowanie odwoławcze, a w dalszej kolejności egzekucyjne. Prowadzimy sprawy rzetelnie i sprawnie, na bieżąco informując Klienta o postępach, a także na bieżąco wyjaśniając aktualną sytuację procesową, niwelując tym samym stres związany z procesem.\r\n\r\nW przypadku sporu zalecamy kontakt z prawnikiem jak najwcześniej. Konsultacja w początkowej fazie sporu często pozwala na sprawniejsze załatwienie sprawy, zminimalizowanie kosztów i zapewnia ochronę przed przedawnieniem.\r\n\r\nŚwiadczymy profesjonalne porady prawne dla klientów indywidualnych oraz przedsiębiorców. Naszym celem jest zapewnienie rzetelnej, zrozumiałej i skutecznej pomocy w rozwiązywaniu problemów prawnych.\r\n\r\nUdzielamy konsultacji zarówno w formie osobistej, jak i online (telefonicznie lub za pośrednictwem wideokonferencji).\r\n\r\nZajmujemy się sprawami z zakresu postępowań <strong>cywilnych, gospodarczych</strong>, w tym <strong>rejestrowych, </strong><strong>rodzinnych, karnych</strong>, a także <strong>podatkowych</strong> i <strong>administracyjnych</strong>.\r\n\r\n&nbsp;\r\n\r\n<strong>a) Sprawy cywilne</strong>\r\n\r\nPrawo cywilne to część prawa, która dotyczy codziennych spraw ludzi – takich jak umowy, spory o pieniądze, sprawy spadkowe, czy prawa do nieruchomości. Jeśli kiedykolwiek kupowałeś coś, pożyczałeś pieniądze, wynajmowałeś mieszkanie, dziedziczyłeś po bliskich, albo miałeś konflikt z sąsiadem – prawdopodobnie zetknąłeś się z prawem cywilnym, nawet o tym nie wiedząc.\r\n\r\nNasza kancelaria pomaga osobom, które potrzebują wsparcia właśnie w takich sytuacjach. Tłumaczymy zawiłości przepisów na prosty język i pomagamy znaleźć najlepsze rozwiązanie problemu – niezależnie od tego, czy chodzi o napisanie pisma, przygotowanie umowy, czy reprezentowanie przed sądem.\r\n\r\nNie musisz znać się na przepisach – od tego jesteśmy my. Wyjaśnimy, doradzimy i zajmiemy się formalnościami. Skontaktuj się z nami i sprawdź, jak możemy Ci pomóc.\r\n\r\n&nbsp;\r\n\r\n<strong>b) Sprawy karne</strong>\r\n\r\nPrawo karne dotyczy sytuacji, w których ktoś jest podejrzany o popełnienie przestępstwa – albo sam padł jego ofiarą. Może chodzić o kradzież, oszustwo, napaść, zniesławienie, prowadzenie pojazdu pod wpływem alkoholu, czy inne zdarzenia, które mogą prowadzić do postępowania karnego. Nasza kancelaria pomaga osobom, które znalazły się w trudnej sytuacji – czy to jako podejrzani, oskarżeni, czy poszkodowani. Reprezentujemy naszych klientów przed policją, prokuraturą i sądem. Czuwamy nad tym, by ich prawa były w pełni respektowane, a sprawa została rzetelnie wyjaśniona.\r\n\r\nJeśli zostałeś wezwany na przesłuchanie, postawiono Ci zarzuty lub czujesz się ofiarą przestępstwa – nie jesteś sam. Skontaktuj się z nami. Wyjaśnimy, co możesz zrobić i zajmiemy się Twoją obroną lub pomocą prawną. Nie musisz przechodzić przez to sam. Skontaktuj się z nami, a przeprowadzimy Cię przez cały proces krok po kroku.\r\n\r\n&nbsp;\r\n\r\n<strong>c) Sprawy podatkowe</strong>\r\n\r\nPrawo podatkowe to dziedzina, która dotyczy obowiązków wobec urzędu skarbowego – zarówno osób prywatnych, jak i firm. Chodzi m.in. o podatki dochodowe, VAT, kwestie rozliczeń, odliczeń, kontroli podatkowych czy sporów z fiskusem. W praktyce – jeśli prowadzisz działalność, pracujesz za granicą, otrzymałeś spadek, sprzedałeś nieruchomość lub urząd skarbowy wysłał Ci pismo, którego nie rozumiesz – prawdopodobnie potrzebujesz porady z zakresu prawa podatkowego. Nasza kancelaria pomaga w zrozumieniu obowiązków podatkowych i rozwiązywaniu problemów z fiskusem. Doradzamy, reprezentujemy przed urzędami, przygotowujemy odwołania i pomagamy uniknąć niepotrzebnych kosztów lub sankcji. Z nami masz pewność, że Twoje sprawy podatkowe są w dobrych rękach. Nie musisz znać się na przepisach – od tego jesteśmy my. Skontaktuj się z nami, a pomożemy Ci bez stresu przejść przez każdą sytuację podatkową.\r\n\r\n&nbsp;\r\n\r\n<strong>d) Sprawy administracyjne</strong>\r\n\r\nPrawo administracyjne dotyczy relacji między obywatelami a urzędami – czyli sytuacji, w których trzeba coś załatwić w instytucji publicznej albo gdy urząd wyda decyzję, z którą się nie zgadzasz. Może chodzić np. o pozwolenie na budowę, decyzję o wycince drzew, meldunek, odmowę przyznania świadczenia, cofnięcie prawa jazdy, decyzję podatkową albo nałożoną karę administracyjną. W takich sprawach często obowiązują konkretne terminy i skomplikowane procedury, które trudno zrozumieć bez pomocy.\r\n\r\nNasza kancelaria pomaga osobom, które mają do czynienia z urzędami. Sporządzamy wnioski, odwołania, skargi i reprezentujemy klientów w postępowaniach administracyjnych oraz przed sądami administracyjnymi. Wyjaśniamy przepisy w prosty sposób i pomagamy skutecznie dochodzić swoich praw.\r\n\r\nJeśli masz problem z decyzją urzędu – nie musisz mierzyć się z tym sam. Skontaktuj się z nami i sprawdź, co możemy dla Ciebie zrobić.\r\n\r\n&nbsp;\r\n\r\n<strong>e) Sprawy rodzinne</strong>\r\n\r\nPrawo rodzinne dotyczy spraw bardzo osobistych – takich jak rozwód, alimenty, opieka nad dziećmi, kontakty z dzieckiem, ustalenie ojcostwa, podział majątku czy ograniczenie władzy rodzicielskiej. To sytuacje, które często wiążą się z silnymi emocjami, stresem i trudnymi decyzjami.\r\n\r\nNasza kancelaria pomaga osobom, które znalazły się w takich trudnych momentach życia. Tłumaczymy skomplikowane przepisy w prosty sposób, doradzamy najlepsze rozwiązania i reprezentujemy naszych klientów w sądzie. Zawsze z poszanowaniem prywatności, zrozumieniem i pełnym zaangażowaniem.\r\n\r\nJeśli stoisz przed rozwodem, masz spór o opiekę nad dzieckiem albo nie wiesz, jak uregulować sprawy rodzinne zgodnie z prawem – jesteśmy tu, by Ci pomóc.'),
