	(168, 38, '_service_list_5_service_list_item', 'field_69de21adc5eb4'),
	(169, 38, 'service_list_6_service_list_item', 'Prowadzenie sprawy w sposób rzetelny, spokojny i uporządkowany'),
	(170, 38, '_service_list_6_service_list_item', 'field_69de21adc5eb4'),
	(171, 38, 'faq_list_0_faq_question', 'Kiedy warto zgłosić się do prawnika w sprawie sporu?'),
	(172, 38, '_faq_list_0_faq_question', 'field_69de21fcc5eb6'),
	(173, 38, 'faq_list_0_faq_answear', 'Najlepiej jak najwcześniej. Konsultacja na początkowym etapie często pozwala lepiej ocenić sytuację, uniknąć niepotrzebnych kosztów, zabezpieczyć dowody oraz podjąć działania przed upływem ważnych terminów.'),
	(174, 38, '_faq_list_0_faq_answear', 'field_69de220ac5eb7'),
	(175, 38, 'faq_list_1_faq_question', 'Czy każda sprawa musi trafić do sądu?'),
	(176, 38, '_faq_list_1_faq_question', 'field_69de21fcc5eb6'),
	(177, 38, 'faq_list_1_faq_answear', 'Nie. W wielu przypadkach możliwe jest wcześniejsze znalezienie rozwiązania polubownego, które pozwala zakończyć spór szybciej i z mniejszym obciążeniem. Przed podjęciem dalszych kroków analizujemy, czy postępowanie sądowe jest rzeczywiście konieczne.'),
	(178, 38, '_faq_list_1_faq_answear', 'field_69de220ac5eb7'),
	(179, 38, 'faq_list_2_faq_question', 'Czy kancelaria może pomóc tylko w przygotowaniu pisma, bez pełnego prowadzenia sprawy?'),
	(180, 38, '_faq_list_2_faq_question', 'field_69de21fcc5eb6'),
	(181, 38, 'faq_list_2_faq_answear', 'Tak. Zakres wsparcia może być dopasowany do potrzeb klienta. Oferujemy zarówno pełne zastępstwo procesowe, jak i pomoc doradczą, obejmującą konsultacje, przygotowanie pism, wniosków oraz wyjaśnienie dalszych kroków.'),
	(182, 38, '_faq_list_2_faq_answear', 'field_69de220ac5eb7'),
	(183, 40, '_wp_attached_file', '2026/04/sprawy-sadowe.jpg'),
