	(201, 43, '_form', '[text* your-name placeholder "Imię i nazwisko"]\n[email* your-email placeholder "Adres e-mail"]\n[tel* your-phone placeholder "Numer telefonu"]\n[textarea your-message placeholder "Wiadomość"]\n\n[acceptance rodo-consent class:consent] Wyrażam zgodę na przetwarzanie moich danych osobowych w celu kontaktu w sprawie zlecenia, zgodnie z <a href="[page_url id:3]">polityką prywatności</a>. \n\n[submit "Wyślij"]'),
	(202, 43, '_mail', 'a:9:{s:6:"active";b:1;s:7:"subject";s:52:"Wiadomość od [your-name] (Kontakt | [_site_title])";s:6:"sender";s:48:"[_site_title] <wordpress@bylica-kancelaria.test>";s:9:"recipient";s:26:"biuro@kancelaria-bylica.pl";s:4:"body";s:190:"<b>Imię i nazwisko:</b> [your-name]\n<b>E-mail:</b> [your-email]\n<b>Telefon:</b> [your-phone]\n\n<span style="display: block; margin: -6px 0;">&nbsp;</span>\n\n<b>Wiadomość:</b>\n[your-message]";s:18:"additional_headers";s:22:"Reply-To: [your-email]";s:11:"attachments";s:0:"";s:8:"use_html";b:1;s:13:"exclude_blank";b:0;}'),
	(203, 43, '_mail_2', 'a:9:{s:6:"active";b:0;s:7:"subject";s:32:"[_site_title] - "[your-subject]"";s:6:"sender";s:48:"[_site_title] <wordpress@bylica-kancelaria.test>";s:9:"recipient";s:12:"[your-email]";s:4:"body";s:268:"Treść wiadomości:\n[your-message]\n\n-- \nTa wiadomość e-mail jest potwierdzeniem wysłania formularza kontaktowego na naszej stronie internetowej ([_site_title] [_site_url]), w którym użyto Twojego adresu e-mail. Jeśli to nie byłeś Ty, zignoruj tę wiadomość.";s:18:"additional_headers";s:29:"Reply-To: [_site_admin_email]";s:11:"attachments";s:0:"";s:8:"use_html";b:1;s:13:"exclude_blank";b:1;}'),
